 public void UiSelectHeirloom(string uid){if(meta.stash.Any(x=>x.uid==uid)){meta.selectedHeirloomUid=uid;SaveSystem.Save(meta);}}
 public bool UiTemper(string uid){var item=meta.stash.FirstOrDefault(x=>x.uid==uid);if(item==null||item.temper>=5)return false;int price=30*(item.temper+1);if(meta.baseGold<price)return false;meta.baseGold-=price;item.temper++;SaveSystem.Save(meta);return true;}
 public bool UiChangeFaction(string id){if(meta.currentFaction==id)return true;if(!GameCatalog.Factions.Any(x=>x.id==id)||meta.baseGold<20)return false;meta.baseGold-=20;meta.currentFaction=id;SaveSystem.Save(meta);return true;}
 public void UiSelectLoadout(string id){LoadoutSystem.Select(meta,id);SaveSystem.Save(meta);}
 public void UiStartExpedition(string dungeonId){StartRun(dungeonId);}
 public RunState UiRun=>run; public string UiMessage=>message; public bool UiPackingAtBase=>packingAtBase;
 public void UiSetAppearance(int bodyValue,int hairValue){meta.body=Mathf.Clamp(bodyValue,0,3);meta.hair=Mathf.Clamp(hairValue,0,2);}
 public void UiFinishCharacter(){meta.characterMade=true;SaveSystem.Save(meta);screen=ScreenId.Hub;scroll=Vector2.zero;}
 public void UiOpenPackingLoadout(string id){LoadoutSystem.Select(meta,id);OpenPacking();}
 public bool UiPackingPlace(string uid,int anchor,int rotation){if(run==null)return false;var item=run.inventory.FirstOrDefault(x=>x.uid==uid);if(item==null||!BackpackSystem.CanPlace(run,item,anchor,rotation,uid))return false;var old=run.placements.FirstOrDefault(x=>x.itemUid==uid);if(old!=null)run.placements.Remove(old);run.placements.Add(new Placement(uid,anchor,rotation));return true;}
 public void UiPackingRemove(string uid){if(run==null)return;var placement=run.placements.FirstOrDefault(x=>x.itemUid==uid);if(placement!=null)run.placements.Remove(placement);}
 public void UiPackingSetBackpack(string id){if(run==null||!GameCatalog.Backpacks.Any(x=>x.id==id))return;run.backpack=id;}
 public void UiPackingToggleCard(string slot){if(run==null)return;if(run.selectedCardSlots.Contains(slot))run.selectedCardSlots.Remove(slot);else if(run.selectedCardSlots.Count<LoadoutSystem.EquipmentCardLimit)run.selectedCardSlots.Add(slot);}
 public void UiPackingSave(){if(run==null)return;LoadoutSystem.Capture(meta,run);meta.selectedBackpack=run.backpack;SaveSystem.Save(meta);screen=packingAtBase?ScreenId.Hub:ScreenId.Map;}
 public void UiTakeReward(string itemId){if(run==null||!GameCatalog.Items.ContainsKey(itemId))return;run.lootBag.Add(new ItemInstance(itemId){identified=false});rewardSelectionId="";screen=ScreenId.Map;}
 public bool UiBuy(string itemId){if(run==null||!GameCatalog.Items.TryGetValue(itemId,out var item))return false;int price=14+item.cells.Length*4;if(run.gold<price)return false;run.gold-=price;run.lootBag.Add(new ItemInstance(itemId){identified=false});message=$"購入完了：{item.name}　残金 {run.gold}G";return true;}
 public void UiReturnToMap(){screen=ScreenId.Map;}
 public void UiResolveEvent(int choice){if(run==null)return;if(choice==0){run.hp=Mathf.Max(1,run.hp-6);run.gold+=24;}else if(choice==1)foreach(var item in run.inventory)item.durability=6;screen=ScreenId.Map;}
 public void UiReturnToHub(){run=null;screen=ScreenId.Hub;scroll=Vector2.zero;}
 Texture2D Solid(Color color){var t=new Texture2D(1,1);t.SetPixel(0,0,color);t.Apply();return t;}
 Texture2D CircleFrame(Color fill,Color rim,int size=96){var t=new Texture2D(size,size,TextureFormat.RGBA32,false);Vector2 c=new((size-1)*.5f,(size-1)*.5f);float radius=size*.485f;for(int y=0;y<size;y++)for(int x=0;x<size;x++){float d=Vector2.Distance(new Vector2(x,y),c);if(d>radius){t.SetPixel(x,y,Color.clear);continue;}float edge=radius-d;Color value=edge<3f?rim:fill;if(edge>5f&&edge<8f)value=Color.Lerp(fill,new Color(1f,.88f,.58f,fill.a),.16f);t.SetPixel(x,y,value);}t.Apply();t.wrapMode=TextureWrapMode.Clamp;t.filterMode=FilterMode.Bilinear;return t;}
 Texture2D RoundedFrame(Color fillTop,Color fillBottom,Color border,int width=64,int height=32,int radius=10){var t=new Texture2D(width,height,TextureFormat.RGBA32,false);float cx=(width-1)*.5f,cy=(height-1)*.5f;for(int y=0;y<height;y++)for(int x=0;x<width;x++){float dx=Mathf.Max(Mathf.Abs(x-cx)-(cx-radius),0),dy=Mathf.Max(Mathf.Abs(y-cy)-(cy-radius),0),distance=Mathf.Sqrt(dx*dx+dy*dy)-radius;if(distance>0){t.SetPixel(x,y,Color.clear);continue;}Color fill=Color.Lerp(fillBottom,fillTop,y/(height-1f));if(distance>-2.2f)fill=border;else if(distance<-4f&&distance>-5.2f)fill=Color.Lerp(fill,new Color(1f,.91f,.70f,fill.a),.12f);t.SetPixel(x,y,fill);}t.Apply();t.wrapMode=TextureWrapMode.Clamp;t.filterMode=FilterMode.Bilinear;return t;}
 Texture2D Framed(Color top,Color bottom,Color border){int size=32;var t=new Texture2D(size,size);for(int y=0;y<size;y++)for(int x=0;x<size;x++){int edge=Mathf.Min(Mathf.Min(x,size-1-x),Mathf.Min(y,size-1-y));Color c=edge<2?border:Color.Lerp(bottom,top,y/(size-1f));if(edge==2)c=Color.Lerp(c,new Color(1,.86f,.48f,1),.22f);t.SetPixel(x,y,c);}t.Apply();t.wrapMode=TextureWrapMode.Clamp;return t;}
 Texture2D AngledPanel(Color top,Color bottom,Color border,int cut=18){int w=160,h=72,b=3;var t=new Texture2D(w,h,TextureFormat.RGBA32,false);for(int y=0;y<h;y++)for(int x=0;x<w;x++){float ny=y/(h-1f);bool outer=x>=cut*(1-ny)&&x<=w-1-cut*ny;bool inner=y>=b&&y<h-b&&x>=cut*(1-ny)+b&&x<=w-1-cut*ny-b;t.SetPixel(x,y,!outer?Color.clear:inner?Color.Lerp(bottom,top,ny):border);}t.Apply();t.wrapMode=TextureWrapMode.Clamp;t.filterMode=FilterMode.Bilinear;return t;}
