racterMade){GUILayout.Label($"◆ {meta.baseGold}G",topChip,GUILayout.Width(Us(125)));GUILayout.Label(GameCatalog.Roles[meta.currentRole].name,topChip,GUILayout.Width(Us(158)));GUILayout.Label(Faction(meta.currentFaction).name,topChip,GUILayout.Width(Us(178)));}GUILayout.EndHorizontal();GUILayout.Space(Us(8));}
