 void Character(){BeginPage("キャラクター作成","探索者の外見を選択してください。体格や髪型による能力差はありません。");GUILayout.BeginHorizontal();GUILayout.BeginVertical(GUILayout.Width(520));GUILayout.Label("体格",header);for(int i=0;i<4;i++){int n=i;string label=$"{(i<2?"男性":"女性")}タイプ {(i%2)+1}";if(GUILayout.Button(meta.body==i?$"● {label}":$"○ {label}",button,GUILayout.Height(54)))meta.body=n;}GUILayout.Space(18);GUILayout.Label("髪型",header);string[] hair={"短髪","ミディアム","結び髪"};for(int i=0;i<3;i++){int n=i;if(GUILayout.Button(meta.hair==i?$"● {hair[i]}":$"○ {hair[i]}",button,GUILayout.Height(54)))meta.hair=n;}GUILayout.Space(24);if(GUILayout.Button($"この姿で始める　{(meta.body<2?"男性":"女性")}／{hair[meta.hair]}",button,GUILayout.Height(68))){meta.characterMade=true;SaveSystem.Save(meta);screen=ScreenId.Hub;}GUILayout.EndVertical();GUILayout.Space(32);Rect preview=GUILayoutUtility.GetRect(520,650,GUILayout.ExpandWidth(true));GUI.DrawTexture(preview,panelTex,ScaleMode.StretchToFill);DrawCharacter(preview,meta.body,meta.hair);GUILayout.EndHorizontal();EndPage();}
 void Hub(){GUILayout.Label($"{Faction(meta.currentFaction).name}の拠点",header);float height=Mathf.Max(620,(Screen.width-82)*9f/16f);Rect art=GUILayoutUtility.GetRect(100,height,GUILayout.ExpandWidth(true));if(hubArt!=null)GUI.DrawTexture(art,hubArt,ScaleMode.ScaleAndCrop);else{GUI.color=new Color(.18f,.15f,.1f);GUI.DrawTexture(art,Texture2D.whiteTexture);GUI.color=Color.white;}Rect hero=new(art.center.x-art.width*.105f,art.y+art.height*.43f,art.width*.21f,art.width*.21f);DrawCharacter(hero,meta.body,meta.hair);hubHover="";HubHotspot(art,new Rect(.02f,.17f,.27f,.42f),"鍛冶場",ScreenId.Vault);HubHotspot(art,new Rect(.01f,.57f,.28f,.38f),"荷造り",ScreenId.Pack);HubHotspot(art,new Rect(.37f,.03f,.25f,.39f),"遠征門",ScreenId.Expedition);HubHotspot(art,new Rect(.75f,.20f,.23f,.36f),"保管庫",ScreenId.Vault);HubHotspot(art,new Rect(.72f,.55f,.27f,.42f),"酒場・図鑑",ScreenId.Compendium);HubHotspot(art,new Rect(.57f,.04f,.24f,.38f),"勢力会館",ScreenId.Faction);HubHotspot(art,new Rect(.39f,.45f,.22f,.43f),GameCatalog.Roles[meta.currentRole].name,ScreenId.Status);}
 Rect FitAspect(Rect target,float aspect){float width=target.width,height=width/Mathf.Max(.01f,aspect);if(height>target.height){height=target.height;width=height*aspect;}return new Rect(target.center.x-width*.5f,target.center.y-height*.5f,width,height);}
 void DrawCharacter(Rect target,int bodyIndex,int hairIndex){if(characterArt==null)return;int col=Mathf.Clamp(bodyIndex,0,3),row=Mathf.Clamp(hairIndex,0,2);Rect uv=new(col*.25f,(2-row)/3f,.25f,1f/3f);float aspect=(uv.width*characterArt.width)/(uv.height*characterArt.height);GUI.DrawTextureWithTexCoords(FitAspect(target,aspect),characterArt,uv,true);}
 void HubHotspot(Rect parent,Rect normalized,string label,ScreenId next){Rect r=new(parent.x+parent.width*normalized.x,parent.y+parent.height*normalized.y,parent.width*normalized.width,parent.height*normalized.height);bool hovered=r.Contains(UnityEngine.Event.current.mousePosition);if(hovered)hubHover=label;if(GUI.Button(r,GUIContent.none,hotspot)){if(next==ScreenId.Pack)OpenPacking();else screen=next;}float labelWidth=Mathf.Clamp(r.width*.72f,120,230);Rect plaque=new(r.center.x-labelWidth*.5f,r.yMax-42,labelWidth,36);GUI.Label(plaque,label,hovered?hubLabelHover:hubLabel);}
 void OpenPacking(){run=LoadoutSystem.CreateRun(meta,"");packingAtBase=true;selectedUid="";message="荷造りセットを編集";screen=ScreenId.Pack;}
 void HubButton(string name,string desc,ScreenId next){if(GUILayout.Button($"{name}\n{desc}",button,GUILayout.Height(110)))screen=next;}
 void Status(){Back();BeginPage("役職ステータス",$"現在職：{GameCatalog.Roles[meta.currentRole].name}");foreach(var level in meta.jobLevels.Where(x=>x.value>0)){var r=GameCatalog.Roles[level.id];GUILayout.BeginVertical(GUI.skin.box);GUILayout.Label($"{r.name}　Lv.{level.value}/{r.maxLevel}",header);GUILayout.Label(r.description,body);GUILayout.Label("Lv.7・最大レベルで専用効果候補を解禁",body);GUILayout.EndVertical();}EndPage();}
 void StatusScreen(){Back();BeginPage("役職ステータス",$"現在職：{GameCatalog.Roles[meta.currentRole].name}");GUILayout.BeginHorizontal();GUILayout.BeginVertical(GUI.skin.box,GUILayout.Width(390));Rect portrait=GUILayoutUtility.GetRect(340,430,GUILayout.ExpandWidth(true));DrawRoleArt(portrait,meta.currentRole);DrawOutline(portrait,gold,3);var current=GameCatalog.Roles[meta.currentRole];GUILayout.Label(current.name,header);GUILayout.Label(current.kind+"\n"+current.description,body);GUILayout.EndVertical();GUILayout.Space(14);GUILayout.BeginVertical(GUILayout.ExpandWidth(true));foreach(var level in meta.jobLevels.Where(x=>x.value>0)){var r=GameCatalog.Roles[level.id];GUILayout.BeginHorizontal(GUI.skin.box,GUILayout.Height(92));Rect icon=GUILayoutUtility.GetRect(72,72,GUILayout.Width(72),GUILayout.Height(72));DrawRoleArt(icon,r.id);DrawOutline(icon,level.id==meta.currentRole?gold:new Color(.38f,.31f,.18f),2);GUILayout.BeginVertical();GUILayout.Label($"{r.name}   Lv.{level.value}/{r.maxLevel}",header);GUILayout.Label(r.description,body);float progress=Mathf.Clamp01(level.value/(float)r.maxLevel);Rect bar=GUILayoutUtility.GetRect(200,9,GUILayout.Height(9));GUI.color=new Color(.05f,.06f,.045f);GUI.DrawTexture(bar,Texture2D.whiteTexture);GUI.color=new Color(.76f,.55f,.20f);GUI.DrawTexture(new Rect(bar.x,bar.y,bar.width*progress,bar.height),Texture2D.whiteTexture);GUI.color=Color.white;GUILayout.EndVertical();GUILayout.EndHorizontal();}GUILayout.EndVertical();GUILayout.EndHorizontal();EndPage();}
 void VaultScreen(){Back();var active=LoadoutSystem.Active(meta);if(string.IsNullOrEmpty(selectedUid)&&meta.stash.Count>0)selectedUid=meta.stash[0].uid;BeginPage("保管庫",$"保管装備 {meta.stash.Count}個　／　家宝と鍛錬を管理します");GUILayout.BeginHorizontal();GUILayout.BeginVertical(GUI.skin.box,GUILayout.Width(BookPageColumnWidth()));GUILayout.Label("現在の荷造り",header);Rect summary=GUILayoutUtility.GetRect(1,66,GUILayout.ExpandWidth(true),GUILayout.Height(66));DrawBookEntrySurface(summary,false);GUI.Label(new Rect(summary.x+15,summary.y+8,summary.width-30,24),active.name,new GUIStyle(header){fontSize=17});string bagName=GameCatalog.Backpacks.FirstOrDefault(x=>x.id==active.backpack)?.name??active.backpack;GUI.Label(new Rect(summary.x+16,summary.y+34,summary.width-32,22),$"{bagName}　・　配置 {active.slots.Count}個",body);GUILayout.Label("編成やバックパックの変更は『荷造り』で行います。",screenSubtitle);GUILayout.Space(12);GUILayout.Label("保管装備一覧",header);DrawStashTiles();GUILayout.EndVertical();GUILayout.Space(BookPageGutter());GUILayout.BeginVertical(GUI.skin.box,GUILayout.Width(BookPageColumnWidth()));DrawStashDetail();GUILayout.EndVertical();GUILayout.EndHorizontal();EndPage();SaveSystem.Save(meta);}
 void DrawStashTiles(){float tileSize=Mathf.Clamp((BookPageColumnWidth()-Us(30))/4f,Us(80),Us(112));int columns=Mathf.Max(2,Mathf.FloorToInt((BookPageColumnWidth()-Us(24))/(tileSize+Us(7))));for(int start=0;start<meta.stash.Count;start+=columns){GUILayout.BeginHorizontal();for(int offset=0;offset<columns;offset++){int index=start+offset;if(index>=meta.stash.Count){GUILayout.Space(tileSize);continue;}var item=meta.stash[index];Rect r=GUILayoutUtility.GetRect(tileSize,tileSize,GUILayout.Width(tileSize),GUILayout.Height(tileSize));GUI.color=selectedUid==item.uid?new Color(1,.82f,.34f):Color.white;DrawItemArt(r,item.templateId);GUI.color=Color.white;DrawOutline(r,item.uid==meta.selectedHeirloomUid?gold:selectedUid==item.uid?new Color(1,.82f,.34f):new Color(.46f,.36f,.20f),item.uid==meta.selectedHeirloomUid?4:2);if(GUI.Button(r,GUIContent.none,hotspot))selectedUid=item.uid;}GUILayout.EndHorizontal();GUILayout.Space(Us(7));}}
 void DrawStashDetail(){var item=meta.stash.FirstOrDefault(x=>x.uid==selectedUid);GUILayout.Label("装備詳細",header);if(item==null){GUILayout.Label("装備アイコンを選択してください。",body);return;}var def=GameCatalog.Items[item.templateId];Rect art=GUILayoutUtility.GetRect(180,180,GUILayout.ExpandWidth(false));DrawItemArt(art,item.templateId);DrawOutline(art,item.uid==meta.selectedHeirloomUid?gold:TypeColor(def.type),3);GUILayout.Label(def.name,header);GUILayout.Label(def.description,body);GUILayout.Label($"{ItemTypeName(def.type)}　{def.cells.Length}マス\n耐久 {item.durability}/6　鍛錬 +{item.temper}\n使用 {item.uses}回　傷跡 {item.scars.Count}",body);if(!string.IsNullOrEmpty(def.linkRule)){GUILayout.Label("LINK",header);GUILayout.Label(def.linkRule,body);}GUILayout.Space(10);if(GUILayout.Button(item.uid==meta.selectedHeirloomUid?"★ 家宝に設定中":"家宝に設定",button,GUILayout.Height(48)))meta.selectedHeirloomUid=item.uid;int price=30*(item.temper+1);GUI.enabled=meta.baseGold>=price&&item.temper<5;if(GUILayout.Button($"{price}Gで鍛錬",button,GUILayout.Height(48))){meta.baseGold-=price;item.temper++;}GUI.enabled=true;}
 void Vault(){Back();var active=LoadoutSystem.Active(meta);BeginPage($"保管庫　{meta.stash.Count}個",$"使用中：{active.name} / {GameCatalog.Backpacks.First(x=>x.id==active.backpack).name}");GUILayout.Label("荷造りセット",header);GUILayout.BeginHorizontal();foreach(var loadout in meta.loadouts){if(GUILayout.Button(loadout.id==meta.selectedLoadoutId?$"● {loadout.name}":loadout.name,button,GUILayout.Height(50)))LoadoutSystem.Select(meta,loadout.id);}GUILayout.EndHorizontal();GUILayout.Space(12);GUILayout.Label("バックパック",header);GUILayout.BeginHorizontal();foreach(var bag in GameCatalog.Backpacks){if(GUILayout.Button(active.backpack==bag.id?$"● {bag.name}":bag.name,button,GUILayout.Height(55))){active.backpack=bag.id;meta.selectedBackpack=bag.id;}}GUILayout.EndHorizontal();GUILayout.Space(12);GUILayout.Label("保管装備",header);foreach(var item in meta.stash){var d=GameCatalog.Items[item.templateId];GUILayout.BeginHorizontal(GUI.skin.box);GUILayout.Label($"{(item.uid==meta.selectedHeirloomUid?"★ ":"")}{d.name} +{item.temper}　耐久{item.durability}/6　使用{item.uses}",body);if(GUILayout.Button("家宝",button,GUILayout.Width(100)))meta.selectedHeirloomUid=item.uid;if(GUILayout.Button("鍛錬",button,GUILayout.Width(100))&&meta.baseGold>=30*(item.temper+1)){meta.baseGold-=30*(item.temper+1);item.temper=Mathf.Min(5,item.temper+1);}GUILayout.EndHorizontal();}EndPage();SaveSystem.Save(meta);}
 void Faction(){Back();BeginPage("勢力関係図","所属変更には20Gが必要です。片方へ肩入れすると、競合勢力との関係にも影響します。");foreach(var f in GameCatalog.Factions){float rep=meta.factionRep.First(x=>x.id==f.id).value;GUILayout.BeginHorizontal(GUI.skin.box);GUILayout.Label($"{f.name}\n貢献 {rep:0}　{f.description}",body,GUILayout.Height(58));if(GUILayout.Button(meta.currentFaction==f.id?"● 所属中":"20Gで所属",button,GUILayout.Width(140),GUILayout.Height(58))&&meta.currentFaction!=f.id&&meta.baseGold>=20){meta.baseGold-=20;meta.currentFaction=f.id;SaveSystem.Save(meta);}GUILayout.EndHorizontal();}EndPage();}
 void Expedition(){Back();BeginPage("遠征準備","使用する荷造りセットと遠征先を選択してください。");GUILayout.Label("荷造りセット",header);GUILayout.BeginHorizontal();foreach(var loadout in meta.loadouts){if(GUILayout.Button(loadout.id==meta.selectedLoadoutId?$"● {loadout.name}":loadout.name,button,GUILayout.Height(52)))LoadoutSystem.Select(meta,loadout.id);}GUILayout.EndHorizontal();var active=LoadoutSystem.Active(meta);GUILayout.Label($"{GameCatalog.Backpacks.First(x=>x.id==active.backpack).name} / 配置{active.slots.Count}個 / 装備カード{active.deck.Count}枚",body);GUILayout.Space(16);GUILayout.Label("遠征先",header);for(int i=0;i<GameCatalog.Dungeons.Length;i++){var d=GameCatalog.Dungeons[i];GUI.enabled=i<meta.dungeonsUnlocked;if(GUILayout.Button($"{d.name}\n{d.description}　戦闘{d.battles}回",button,GUILayout.Height(88))){StartRun(d.id);}GUI.enabled=true;}EndPage();SaveSystem.Save(meta);}
 void StartRun(string dungeon){try{message="ダンジョンを生成中…";run=LoadoutSystem.CreateRun(meta,dungeon);packingAtBase=false;map=DungeonSystem.Generate(dungeon);if(map==null||map.zones==null||map.zones.Count==0)throw new Exception("区域データを生成できませんでした");screen=ScreenId.Map;selectedUid="";scroll=Vector2.zero;message=$"区域1：{DungeonSystem.CurrentZone(map).name}へ進入";}catch(Exception ex){run=null;map=null;screen=ScreenId.Expedition;message="遠征開始エラー："+ex.Message;Debug.LogException(ex);}}
 void PackingScreen(){BeginPage("荷造り","左頁で配置を組み、右頁で必要な情報だけを切り替えて確認します。");GUILayout.BeginHorizontal();GUILayout.BeginVertical(GUI.skin.box,GUILayout.Width(BookPageColumnWidth()));GUILayout.Label("荷造り盤",header);float packingActionWidth=Mathf.Max(62f,(BookPageColumnWidth()-50f)/3f);GUILayout.BeginHorizontal();if(GUILayout.Button(packingAtBase?"← 拠点":"← マップ",button,GUILayout.Width(packingActionWidth),GUILayout.Height(42)))screen=packingAtBase?ScreenId.Hub:ScreenId.Map;if(GUILayout.Button("↻ 回転",button,GUILayout.Width(packingActionWidth),GUILayout.Height(42)))selectedRotation=(selectedRotation+1)%4;if(GUILayout.Button("選択解除",button,GUILayout.Width(packingActionWidth),GUILayout.Height(42))){selectedUid="";message="選択を解除しました";}GUILayout.EndHorizontal();if(!string.IsNullOrEmpty(message))GUILayout.Label(message,new GUIStyle(body){fontStyle=FontStyle.Bold},GUILayout.Height(24));GUILayout.Space(5);DrawGrid();GUILayout.Space(10);GUILayout.Label("所持装備　―　挿絵を選択",header);DrawInventoryTiles();GUILayout.EndVertical();GUILayout.Space(BookPageGutter());GUILayout.BeginVertical(GUI.skin.box,GUILayout.Width(BookPageColumnWidth()));var active=LoadoutSystem.Active(meta);GUILayout.Label($"{active.name}　／　{GameCatalog.Backpacks.FirstOrDefault(x=>x.id==run.backpack)?.name??run.backpack}",header);DrawPackingTabs();GUILayout.Space(8);if(packingDetailTab==0)DrawItemDetail();else if(packingDetailTab==1)DrawPackingDeck();else DrawPackingEffects();GUILayout.FlexibleSpace();if(GUILayout.Button("この荷造りを保存",button,GUILayout.Height(56))){LoadoutSystem.Capture(meta,run);SaveSystem.Save(meta);screen=packingAtBase?ScreenId.Hub:ScreenId.Map;}GUILayout.EndVertical();GUILayout.EndHorizontal();EndPage();}
 void DrawPackingTabs(){string[] labels={"装備詳細","カード","発動効果"};float width=Mathf.Max(Us(72),(BookPageColumnWidth()-Us(12))/3f);GUILayout.BeginHorizontal();for(int i=0;i<labels.Length;i++){int tab=i;if(GUILayout.Button((packingDetailTab==i?"● ":"")+labels[i],packingDetailTab==i?navSelected:navButton,GUILayout.Width(width),GUILayout.Height(Us(50))))packingDetailTab=tab;}GUILayout.EndHorizontal();}
 void DrawPackingDeck(){var build=BackpackSystem.Build(run);GUILayout.Label($"装備カード　{run.selectedCardSlots.Count}/{LoadoutSystem.EquipmentCardLimit}",header);GUILayout.Label("配置した装備から、戦闘へ持ち込むカードを選択します。",body);foreach(var c in build.candidates){bool chosen=run.selectedCardSlots.Contains(c.slotKey);GUI.enabled=chosen||run.selectedCardSlots.Count<LoadoutSystem.EquipmentCardLimit;if(GUILayout.Button($"{(chosen?"●":"○")} {c.name}　{c.cost}EN\n{c.text}",chosen?navSelected:card,GUILayout.Height(62))){if(chosen)run.selectedCardSlots.Remove(c.slotKey);else run.selectedCardSlots.Add(c.slotKey);}GUI.enabled=true;}GUILayout.Space(7);GUILayout.Label($"役職カード {build.roleCards.Count}枚　／　合計デッキ {build.deck.Count}枚",body);}
 void DrawPackingEffects(){var build=BackpackSystem.Build(run);GUILayout.Label("属性一致",header);GUILayout.Label("装備の属性と収納面が一致した数です。配置を変えると即座に更新されます。",body);Element[] elements={Element.Fire,Element.Water,Element.Wind,Element.Earth};GUILayout.BeginHorizontal();foreach(var element in elements){int count=CountMatchedCells(element);Rect chip=GUILayoutUtility.GetRect(72,58,GUILayout.Width(72),GUILayout.Height(58));GUI.Box(chip,GUIContent.none,bookEntryStyle);GUI.color=ElementColor(element)*new Color(1.8f,1.8f,1.8f,.72f);GUI.DrawTexture(new Rect(chip.x+7,chip.y+7,12,chip.height-14),Texture2D.whiteTexture);GUI.color=Color.white;GUI.Label(new Rect(chip.x+24,chip.y+6,chip.width-28,22),ElementLabel(element),new GUIStyle(body){fontSize=12,fontStyle=FontStyle.Bold});GUI.Label(new Rect(chip.x+24,chip.y+27,chip.width-28,24),count.ToString(),new GUIStyle(header){fontSize=19});}GUILayout.EndHorizontal();GUILayout.Space(12);GUILayout.Label("発動中LINK",header);if(build.links.Count==0)GUILayout.Label("隣接条件を満たすLINKはまだありません。",body);else foreach(var link in build.links)GUILayout.Label("◆ "+link,new GUIStyle(body){fontStyle=FontStyle.Bold},GUILayout.MinHeight(25));}
 int CountMatchedCells(Element target){int count=0;foreach(var p in run.placements){var item=run.inventory.FirstOrDefault(x=>x.uid==p.itemUid);if(item==null||!GameCatalog.Items.TryGetValue(item.templateId,out var def))continue;foreach(var cell in BackpackSystem.Layout(def,p.rotation,item)){int index=p.anchor+cell.pos.y*6+cell.pos.x;if(index>=0&&index<GameCatalog.Board.Length&&cell.element==target&&GameCatalog.Board[index]==target)count++;}}return count;}
 void DrawInventoryTiles(){float tileSize=Mathf.Clamp((BookPageColumnWidth()-Us(30))/4f,Us(78),Us(112));int columns=Mathf.Max(2,Mathf.FloorToInt((BookPageColumnWidth()-Us(24))/(tileSize+Us(6))));for(int start=0;start<run.inventory.Count;start+=columns){GUILayout.BeginHorizontal();for(int offset=0;offset<columns;offset++){int index=start+offset;if(index>=run.inventory.Count){GUILayout.Space(tileSize);continue;}var item=run.inventory[index];bool placed=run.placements.Any(x=>x.itemUid==item.uid),selected=selectedUid==item.uid;Rect r=GUILayoutUtility.GetRect(tileSize,tileSize,GUILayout.Width(tileSize),GUILayout.Height(tileSize));GUI.color=selected?new Color(1,.82f,.34f,1):placed?new Color(.62f,.68f,.58f,.72f):Color.white;DrawItemArt(r,item.templateId);GUI.color=Color.white;if(selected)DrawOutline(r,gold,3);else DrawOutline(r,placed?new Color(.43f,.66f,.42f):new Color(.46f,.36f,.20f),2);if(placed)GUI.Label(new Rect(r.xMax-Us(30),r.y+Us(4),Us(26),Us(26)),"✓",hubLabel);if(GUI.Button(r,GUIContent.none,hotspot)){selectedUid=item.uid;selectedRotation=run.placements.FirstOrDefault(x=>x.itemUid==item.uid)?.rotation??0;message=GameCatalog.Items[item.templateId].name+"を選択";}}GUILayout.EndHorizontal();GUILayout.Space(Us(6));}}
 void DrawItemDetail(){var item=run.inventory.FirstOrDefault(x=>x.uid==selectedUid);GUILayout.Label("装備詳細",header);if(item==null){GUILayout.Label("左の装備アイコンを選択してください。",body);return;}var def=GameCatalog.Items[item.templateId];Rect art=GUILayoutUtility.GetRect(150,150,GUILayout.ExpandWidth(false));DrawItemArt(art,item.templateId);DrawOutline(art,TypeColor(def.type),3);GUILayout.Label(def.name,header);GUILayout.Label(def.description,body);GUILayout.Space(6);GUILayout.Label($"分類　{ItemTypeName(def.type)}\n形状　{def.cells.Length}マス\n耐久　{item.durability}/6\n鍛錬　+{item.temper}",body);GUILayout.Space(6);GUILayout.Label("属性　"+string.Join("・",def.cells.Select((c,i)=>ElementLabel(item.colors!=null&&i<item.colors.Count?item.colors[i]:c.element))),body);if(!string.IsNullOrEmpty(item.traitId))GUILayout.Label("個体特性　"+item.traitId,body);if(!string.IsNullOrEmpty(def.linkRule)){GUILayout.Label("LINK",header);GUILayout.Label(def.linkRule,body);}GUILayout.Label("生成カード",header);foreach(var id in def.cardIds??new[]{def.cardId})if(GameCatalog.Cards.TryGetValue(id,out var c))GUILayout.Label($"◆ {c.name}　{c.cost}EN\n　{c.text}",body);}
 void DrawItemArt(Rect target,string itemId){if(equipmentArt==null)return;GUI.DrawTextureWithTexCoords(target,equipmentArt,ItemArtUV(itemId),true);}
 void DrawItemArtCell(Rect target,string itemId,int cellX,int cellY,int width,int height){if(equipmentArt==null)return;Rect source=ItemArtUV(itemId);Rect uv=new(source.x+source.width*cellX/width,source.y+source.height*(height-1-cellY)/height,source.width/width,source.height/height);GUI.DrawTextureWithTexCoords(target,equipmentArt,uv,true);}
 Rect ItemArtUV(string itemId){int index=ItemArtIndex(itemId),col=index%4,row=index/4;return new Rect(col*.25f,(2-row)/3f,.25f,1f/3f);}
 Rect CropAtlasUvToAspect(Rect uv,Texture2D texture,float targetAspect){if(texture==null||targetAspect<=0f)return uv;float sourceAspect=(uv.width*texture.width)/(uv.height*texture.height);if(sourceAspect>targetAspect){float width=uv.height*texture.height*targetAspect/texture.width;uv.x+=(uv.width-width)*.5f;uv.width=width;}else if(sourceAspect<targetAspect){float height=uv.width*texture.width/(targetAspect*texture.height);uv.y+=(uv.height-height)*.5f;uv.height=height;}return uv;}
 void DrawAtlasArt(Rect target,Texture2D texture,Rect uv){if(texture==null||target.width<=0f||target.height<=0f)return;GUI.DrawTextureWithTexCoords(target,texture,CropAtlasUvToAspect(uv,texture,target.width/target.height),true);}
 void DrawDungeonArt(Rect target,string dungeon){if(dungeonArt==null)return;Rect uv=dungeon=="hollow_archive"?new Rect(.5f,.5f,.5f,.5f):dungeon=="ash_forge"?new Rect(.5f,0,.5f,.5f):new Rect(0,.5f,.5f,.5f);DrawAtlasArt(target,dungeonArt,uv);}
 int ItemArtIndex(string id)=>id=="sword"?0:id=="shield"?1:id=="ember"?2:id=="herb"?3:id=="dagger"?4:id=="plate"?5:id=="crystal"?6:id=="bomb"?7:id=="spear"?8:id=="buckler"?9:id=="flask"?10:id=="charm"?11:0;
 void DrawOutline(Rect r,Color color,float thickness){GUI.color=color;GUI.DrawTexture(new Rect(r.x,r.y,r.width,thickness),Texture2D.whiteTexture);GUI.DrawTexture(new Rect(r.x,r.yMax-thickness,r.width,thickness),Texture2D.whiteTexture);GUI.DrawTexture(new Rect(r.x,r.y,thickness,r.height),Texture2D.whiteTexture);GUI.DrawTexture(new Rect(r.xMax-thickness,r.y,thickness,r.height),Texture2D.whiteTexture);GUI.color=Color.white;}
 string ItemTypeName(ItemType type)=>type==ItemType.Weapon?"武器":type==ItemType.Armor?"防具":type==ItemType.Rune?"ルーン":"消耗品";
 void Pack(){GUILayout.BeginHorizontal();if(GUILayout.Button(packingAtBase?"← 拠点":"← マップ",GUILayout.Width(100)))screen=packingAtBase?ScreenId.Hub:ScreenId.Map;if(GUILayout.Button("↻ 回転",GUILayout.Width(100)))selectedRotation=(selectedRotation+1)%4;if(GUILayout.Button("選択を外す",GUILayout.Width(110)))selectedUid="";GUILayout.Label(message,body);GUILayout.EndHorizontal();GUILayout.BeginHorizontal();GUILayout.BeginVertical(GUILayout.Width(250));GUILayout.Label("保管装備",header);foreach(var item in run.inventory){var d=GameCatalog.Items[item.templateId];bool placed=run.placements.Any(x=>x.itemUid==item.uid);GUI.enabled=!placed;if(GUILayout.Button($"{d.name}\n{d.description}",card,GUILayout.Height(65))){selectedUid=item.uid;selectedRotation=0;}GUI.enabled=true;}GUILayout.EndVertical();GUILayout.Space(18);DrawGrid();GUILayout.Space(18);GUILayout.BeginVertical(GUILayout.Width(320));var build=BackpackSystem.Build(run);GUILayout.Label($"装備カード {build.deck.Count-build.roleCards.Count}/8　基本カード {build.roleCards.Count}",header);foreach(var c in build.candidates){bool selected=run.selectedCardSlots.Contains(c.slotKey);GUI.enabled=selected||run.selectedCardSlots.Count<LoadoutSystem.EquipmentCardLimit;if(GUILayout.Button($"{(selected?"●":"○")} {c.name} [{c.cost}]\n{c.text}\n{c.source}",card,GUILayout.Height(74))){if(selected)run.selectedCardSlots.Remove(c.slotKey);else run.selectedCardSlots.Add(c.slotKey);}GUI.enabled=true;}GUILayout.Label("発動中リンク",header);foreach(var link in build.links)GUILayout.Label("・"+link,body);GUILayout.EndVertical();GUILayout.EndHorizontal();if(GUILayout.Button("この荷造りを保存",button,GUILayout.Height(55))){LoadoutSystem.Capture(meta,run);SaveSystem.Save(meta);screen=packingAtBase?ScreenId.Hub:ScreenId.Map;}}
void DrawGrid(){float gridWidth=Mathf.Max(204f,BookPageColumnWidth()-Us(44)),gridHeight=gridWidth*4f/6f;GUILayout.BeginVertical(GUILayout.Width(gridWidth));GUILayout.Label("属性バックパック",header);GUILayout.Label("淡い属性色と装備の属性を合わせつつ、隣接LINKを組み立てます。",body);GUILayout.Space(Us(8));Rect grid=GUILayoutUtility.GetRect(gridWidth,gridHeight,GUILayout.Width(gridWidth),GUILayout.Height(gridHeight));Rect frame=new(grid.x-Us(18),grid.y-Us(18),grid.width+Us(36),grid.height+Us(36));GUI.DrawTexture(frame,backpackLeatherTex,ScaleMode.StretchToFill,true);DrawBackpackDecor(frame);float cw=grid.width/6,ch=grid.height/4;for(int i=0;i<24;i++){Rect r=new(grid.x+(i%6)*cw+Us(3),grid.y+(i/6)*ch+Us(3),cw-Us(6),ch-Us(6));GUI.DrawTexture(r,backpackPocketTex,ScaleMode.StretchToFill,true);Color tint=ElementColor(GameCatalog.Board[i]);GUI.color=new Color(tint.r,tint.g,tint.b,.18f);GUI.DrawTexture(new Rect(r.x+Us(4),r.y+Us(4),r.width-Us(8),r.height-Us(8)),bookChipTex,ScaleMode.StretchToFill,true);GUI.color=Color.white;if(GUI.Button(r,GUIContent.none,cellButton))TryPlace(i);}DrawPlacementGhost(grid,cw,ch);foreach(var p in run.placements.ToList()){var item=run.inventory.First(x=>x.uid==p.itemUid);var def=GameCatalog.Items[item.templateId];var layout=BackpackSystem.Layout(def,p.rotation,item);int pieceWidth=layout.Max(x=>x.pos.x)+1,pieceHeight=layout.Max(x=>x.pos.y)+1;foreach(var cell in layout){int px=p.anchor%6+cell.pos.x,py=p.anchor/6+cell.pos.y;if(px<0||px>=6||py<0||py>=4)continue;int index=py*6+px;Rect r=new(grid.x+px*cw+Us(7),grid.y+py*ch+Us(7),cw-Us(14),ch-Us(14));bool match=GameCatalog.Board[index]==cell.element;GUI.color=new Color(.025f,.022f,.018f,.92f);GUI.DrawTexture(r,backpackPocketTex,ScaleMode.StretchToFill,true);GUI.color=Color.white;DrawItemArtCell(r,item.templateId,cell.pos.x,cell.pos.y,pieceWidth,pieceHeight);GUI.color=match?new Color(1f,.79f,.31f,.13f):new Color(1,1,1,.035f);GUI.DrawTexture(r,Texture2D.whiteTexture);GUI.color=Color.white;DrawOutline(r,match?gold:new Color(.30f,.25f,.16f),