void DrawBackpackDecor(Rect frame){Color stitch=new(.72f,.49f,.22f,.66f);GUI.color=new Color(.04f,.025f,.015f,.82f);GUI.DrawTexture(new Rect(frame.center.x-Us(50),frame.y-Us(13),Us(100),Us(19)),backpackLeatherTex,ScaleMode.StretchToFill,true);GUI.color=stitch;for(float x=frame.x+Us(13);x<frame.xMax-Us(13);x+=Us(12)){GUI.DrawTexture(new Rect(x,frame.y+Us(8),Us(6),Us(2)),Texture2D.whiteTexture);GUI.DrawTexture(new Rect(x,frame.yMax-Us(10),Us(6),Us(2)),Texture2D.whiteTexture);}for(float y=frame.y+Us(14);y<frame.yMax-Us(14);y+=Us(12)){GUI.DrawTexture(new Rect(frame.x+Us(8),y,Us(2),Us(6)),Texture2D.whiteTexture);GUI.DrawTexture(new Rect(frame.xMax-Us(10),y,Us(2),Us(6)),Texture2D.whiteTexture);}GUI.color=Color.white;}
void DrawPlacementGhost(Rect grid,float cw,float ch){if(string.IsNullOrEmpty(selectedUid)||!grid.Contains(UnityEngine.Event.current.mousePosition))return;var item=run.inventory.FirstOrDefault(x=>x.uid==selectedUid);if(item==null||!GameCatalog.Items.TryGetValue(item.templateId,out var def))return;Vector2 mouse=UnityEngine.Event.current.mousePosition;int ax=Mathf.Clamp(Mathf.FloorToInt((mouse.x-grid.x)/cw),0,5),ay=Mathf.Clamp(Mathf.FloorToInt((mouse.y-grid.y)/ch),0,3),anchor=ay*6+ax;bool canPlace=BackpackSystem.CanPlace(run,item,anchor,selectedRotation,selectedUid);var layout=BackpackSystem.Layout(def,selectedRotation,item);int pieceWidth=layout.Max(x=>x.pos.x)+1,pieceHeight=layout.Max(x=>x.pos.y)+1;foreach(var cell in layout){int x=ax+cell.pos.x,y=ay+cell.pos.y;if(x<0||x>=6||y<0||y>=4)continue;Rect r=new(grid.x+x*cw+4,grid.y+y*ch+4,cw-8,ch-8);GUI.color=canPlace?new Color(.37f,.82f,.45f,.38f):new Color(.92f,.20f,.17f,.42f);GUI.DrawTexture(r,Texture2D.whiteTexture);GUI.color=new Color(1f,1f,1f,.58f);DrawItemArtCell(r,item.templateId,cell.pos.x,cell.pos.y,pieceWidth,pieceHeight);GUI.color=Color.white;DrawOutline(r,canPlace?new Color(.78f,.92f,.48f):new Color(1f,.28f,.22f),3);}Rect hint=new(mouse.x+14,mouse.y-31,canPlace?92:122,27);GUI.Box(hint,GUIContent.none,canPlace?bookEntrySelectedStyle:bookEntryStyle);GUI.Label(hint,canPlace?"配置できます":"ここには置けません",new GUIStyle(body){fontSize=11,fontStyle=FontStyle.Bold,alignment=TextAnchor.MiddleCenter,normal={textColor=canPlace?new Color(.22f,.42f,.16f):new Color(.66f,.15f,.11f)}});}
void RemoveSelectedPlacement(){var placement=run.placements.FirstOrDefault(x=>x.itemUid==selectedUid);if(placement==null)return;var item=run.inventory.FirstOrDefault(x=>x.uid==selectedUid);run.placements.Remove(placement);message=(item!=null&&GameCatalog.Items.TryGetValue(item.templateId,out var def)?def.name:"装備")+"を外しました";}
