 void TryPlace(int cell){if(string.IsNullOrEmpty(selectedUid))return;var item=run.inventory.FirstOrDefault(x=>x.uid==selectedUid);if(item==null)return;var old=run.placements.FirstOrDefault(x=>x.itemUid==selectedUid);if(BackpackSystem.CanPlace(run,item,cell,selectedRotation,selectedUid)){if(old!=null)run.placements.Remove(old);run.placements.Add(new Placement(item.uid,cell,selectedRotation));message=GameCatalog.Items[item.templateId].name+"を配置";}else message="そこには入りません";}
 void Map(){BeginPage("ダンジョン探索",GameCatalog.Dungeons.First(x=>x.id==run.dungeon).name);GUILayout.BeginHorizontal();if(GUILayout.Button("荷造り",button,GUILayout.Width(120),GUILayout.Height(48)))screen=ScreenId.Pack;if(GUILayout.Button("入口から帰還",button,GUILayout.Width(150),GUILayout.Height(48))&&map.current==12){EndPage();FinishRun(true);return;}GUILayout.FlexibleSpace();GUILayout.Label($"警戒 {run.axes.alert:+#;-#;0}",StateStyle(run.axes.alert),GUILayout.Width(130),GUILayout.Height(48));GUILayout.Label($"崩壊 {run.axes.collapse:+#;-#;0}",StateStyle(run.axes.collapse),GUILayout.Width(130),GUILayout.Height(48));GUILayout.Label($"汚染 {run.axes.corruption:+#;-#;0}",StateStyle(run.axes.corruption),GUILayout.Width(130),GUILayout.Height(48));GUILayout.EndHorizontal();GUILayout.Space(12);Rect area=GUILayoutUtility.GetRect(720,600,GUILayout.ExpandWidth(true));DrawDungeonArt(area,run.dungeon);GUI.color=new Color(.02f,.035f,.025f,.36f);GUI.DrawTexture(area,Texture2D.whiteTexture);GUI.color=Color.white;DrawOutline(area,new Color(.65f,.48f,.20f),3);float w=area.width/6,h=area.height/6;foreach(var n in map.nodes){Rect r=new(area.x+n.x*w+16,area.y+n.y*h+16,w-32,h-32);GUI.enabled=n.revealed&&(n.id==map.current||DungeonSystem.Adjacent(map.current,n.id));GUI.backgroundColor=n.id==map.current?gold:n.visited?new Color(.25f,.35f,.25f):panel;string icon=n.type=="battle"?"⚔":n.type=="boss"?"♛":n.type=="shop"?"商":n.type=="rest"?"休":n.type=="treasure"?"宝":n.type=="event"?"？":n.type=="entrance"?"入":"・";if(GUI.Button(r,n.revealed?$"{icon}\n{NodeName(n.type)}":"？",button)){if(n.id!=map.current&&DungeonSystem.Move(map,n.id,run))EnterNode(n);}GUI.backgroundColor=Color.white;GUI.enabled=true;}EndPage();}
 GUIStyle StateStyle(int value)=>new GUIStyle(hubLabel){normal={background=buttonTex,textColor=value>=10?new Color(.95f,.45f,.35f):value<=-10?new Color(.55f,.82f,.65f):gold}};
 string NodeName(string type)=>type=="battle"?"戦闘":type=="boss"?"区域主":type=="gate"?"区域門":type=="shop"?"商人":type=="rest"?"野営":type=="treasure"?"宝物":type=="event"?"イベント":type=="entrance"?"入口":"未踏";
 void EnterNode(MapNode n){if(n.cleared&&n.type!="shop")return;if(n.type=="battle"||n.type=="boss"){StartBattle(n.type=="boss");return;}if(n.type=="gate"){message="区域門へ到達した";return;}if(n.type=="shop"){screen=ScreenId.Shop;return;}if(n.type=="event"||n.type=="treasure"){n.cleared=true;mapEventNodeId=n.id;mapEventOverlay=true;message=n.type=="treasure"?"封じられた戦利品を発見":"記憶の揺らぎが道を覆った";return;}if(n.type=="rest"){n.cleared=true;run.hp=Mathf.Min(run.maxHp,run.hp+12);foreach(var i in run.inventory)i.durability=6;message="野営して回復・修理した";}else n.cleared=true;}
 void DrawMapEventOverlay(){Rect full=new(0,0,Screen.width,Screen.height);GUI.color=new Color(.006f,.008f,.009f,.74f);GUI.DrawTexture(full,Texture2D.whiteTexture);GUI.color=Color.white;DrawEventMist(full);var node=map?.nodes.FirstOrDefault(x=>x.id==mapEventNodeId);bool treasure=node!=null&&node.type=="treasure";Rect panel=new(Screen.width*.145f,Screen.height*.095f,Screen.width*.71f,Screen.height*.80f);GUI.color=new Color(.015f,.016f,.014f,.97f);GUI.DrawTexture(panel,Texture2D.whiteTexture);GUI.color=Color.white;DrawOutline(panel,new Color(.67f,.48f,.20f,.92f),3);GUI.Label(new Rect(panel.x+28,panel.y+18,panel.width-56,44),treasure?"封印された遺物":"記憶の揺らぎ",new GUIStyle(screenTitle){fontSize=Mathf.RoundToInt(Mathf.Clamp(Screen.width*.021f,25f,36f)),fontStyle=FontStyle.Bold,alignment=TextAnchor.MiddleCenter,normal={textColor=new Color(.96f,.82f,.52f)}});GUI.Label(new Rect(panel.x+40,panel.y+61,panel.width-80,25),treasure?"地図の上へ、所有者を失った記憶が滲み出している。":"周囲の道が黒い靄に沈み、まだ記されていない選択だけが浮かび上がる。",new GUIStyle(body){fontSize=15,alignment=TextAnchor.MiddleCenter,normal={textColor=new Color(.77f,.74f,.66f)}});float leftW=panel.width*.43f;Rect scene=new(panel.x+30,panel.y+102,leftW-42,panel.height-142);GUI.color=new Color(.50f,.44f,.36f,.78f);DrawDungeonArt(scene,run.dungeon);GUI.color=treasure?new Color(.45f,.27f,.04f,.28f):new Color(.20f,.03f,.28f,.38f);GUI.DrawTexture(scene,Texture2D.whiteTexture);GUI.color=Color.white;DrawOutline(scene,new Color(.58f,.41f,.19f,.82f),2);GUI.Label(new Rect(scene.x,scene.center.y-50,scene.width,100),treasure?"✦":"？",new GUIStyle(title){fontSize=68,fontStyle=FontStyle.Bold,alignment=TextAnchor.MiddleCenter,normal={textColor=new Color(1f,.82f,.38f,.88f)}});GUI.Label(new Rect(scene.x+18,scene.yMax-88,scene.width-36,68),treasure?"錆びた封印の奥で、何かがこちらの気配を待っている。":"紫の残光が呼吸するように明滅し、探索者の記憶へ触れようとしている。",new GUIStyle(body){fontSize=14,wordWrap=true,alignment=TextAnchor.MiddleCenter,normal={textColor=new Color(.92f,.87f,.75f)}});float rightX=panel.x+leftW+18,rightW=panel.xMax-rightX-30,choiceH=(panel.height-142-22)/3f;if(DrawOverlayChoice(new Rect(rightX,panel.y+102,rightW,choiceH),"代償を支払う","HP -6　／　24Gを獲得",new Color(.58f,.17f,.18f))){run.hp=Mathf.Max(1,run.hp-6);run.gold+=24;CloseMapEvent("代償を払い、24Gを得た");}if(DrawOverlayChoice(new Rect(rightX,panel.y+102+choiceH+11,rightW,choiceH),"残響を修復する","すべての装備の耐久を回復",new Color(.18f,.45f,.36f))){foreach(var item in run.inventory)item.durability=6;CloseMapEvent("残響が装備を修復した");}if(DrawOverlayChoice(new Rect(rightX,panel.y+102+(choiceH+11)*2,rightW,choiceH),"靄を振り払う","何も得ず、地図の探索へ戻る",new Color(.42f,.34f,.24f)))CloseMapEvent("黒い靄を振り払い、探索へ戻った");}
 void DrawEventMist(Rect full){Rect[] clouds={new(-80,full.height*.10f,full.width*.46f,full.height*.30f),new(full.width*.62f,full.height*.05f,full.width*.45f,full.height*.33f),new(-120,full.height*.62f,full.width*.52f,full.height*.35f),new(full.width*.66f,full.height*.60f,full.width*.44f,full.height*.36f),new(full.width*.25f,-80,full.width*.50f,full.height*.25f),new(full.width*.26f,full.height*.78f,full.width*.49f,full.height*.27f)};foreach(var cloud in clouds){GUI.color=new Color(0,0,0,.42f);GUI.DrawTexture(cloud,bookChipTex,ScaleMode.StretchToFill,true);}GUI.color=Color.white;}
