 void CloseMapEvent(string result){mapEventOverlay=false;mapEventNodeId=-1;message=result;selectedMapNodeId=map.current;}
 void StartBattle(bool boss){var dungeon=GameCatalog.Dungeons.First(x=>x.id==run.dungeon);var pool=GameCatalog.Enemies.Where(x=>boss?x.tier==3:x.tier==Mathf.Min(2,1+run.battlesWon/3)).ToArray();battle=BattleSystem.Begin(run,pool[UnityEngine.Random.Range(0,pool.Length)],dungeon.hpScale);screen=ScreenId.Battle;}
 void BattleScreen(){var dungeon=GameCatalog.Dungeons.First(x=>x.id==run.dungeon);BeginPage("戦闘",dungeon.name);GUILayout.BeginHorizontal();Rect playerPanel=GUILayoutUtility.GetRect(360,280,GUILayout.ExpandWidth(true));DrawCombatPortrait(playerPanel,true);GUILayout.Space(18);GUILayout.Label("対",title,GUILayout.Width(52),GUILayout.Height(280));GUILayout.Space(18);Rect enemyPanel=GUILayoutUtility.GetRect(360,280,GUILayout.ExpandWidth(true));DrawCombatPortrait(enemyPanel,false);GUILayout.EndHorizontal();GUILayout.Space(8);GUILayout.Label(battle.log,hubLabel,GUILayout.Height(42));if(run.consumables.Count>0){GUILayout.BeginHorizontal();GUILayout.Label("消耗品",header,GUILayout.Width(80));for(int i=0;i<run.consumables.Count;i++){int index=i;if(GUILayout.Button(ConsumableSystem.Name(run.consumables[i]),button,GUILayout.Width(120),GUILayout.Height(46))){ConsumableSystem.Use(run,battle,index);if(battle.enemyHp<=0){EndPage();WinBattle();return;}break;}}GUILayout.EndHorizontal();}GUILayout.Space(14);GUILayout.Label("手札",header);GUILayout.BeginHorizontal();for(int i=0;i<run.hand.Count;i++){int index=i;var c=run.hand[i];GUI.enabled=c.cost<=run.energy;GUI.backgroundColor=c.type==CardType.Attack?new Color(.42f,.15f,.12f):c.type==CardType.Skill?new Color(.11f,.29f,.36f):new Color(.30f,.17f,.39f);if(GUILayout.Button($"{c.cost} EN\n{c.name}\n\n{c.text}\n\n{c.source}",card,GUILayout.Width(165),GUILayout.Height(190))){if(BattleSystem.Play(run,battle,index)){GUI.backgroundColor=Color.white;EndPage();WinBattle();return;}}GUI.backgroundColor=Color.white;GUI.enabled=true;}GUILayout.EndHorizontal();GUILayout.Space(14);GUI.backgroundColor=new Color(.54f,.17f,.13f);if(GUILayout.Button("ターン終了",button,GUILayout.Width(180),GUILayout.Height(56))){GUI.backgroundColor=Color.white;if(BattleSystem.EndTurn(run,battle,dungeon.damage)){EndPage();FinishRun(false);return;}}GUI.backgroundColor=Color.white;EndPage();}
 void DrawCombatPortrait(Rect target,bool player){GUI.Box(target,GUIContent.none,bookEntryStyle);Rect art=new(target.x+12,target.y+6,target.width-24,target.height-12);GUI.color=player?new Color(.54f,.66f,.58f,.10f):new Color(.68f,.38f,.29f,.10f);GUI.DrawTexture(art,bookHoverTex);GUI.color=Color.white;DrawBattleActorArt(art,player);Rect info=new(target.x+12,target.yMax-98,target.width-24,86);var infoStyle=new GUIStyle(bookEntryStyle){normal={background=bookChipTex}};GUI.Box(info,GUIContent.none,infoStyle);string actor=player?GameCatalog.Roles[run.role].name:battle.enemy.name;var actorStyle=new GUIStyle(header){fontSize=17,clipping=TextClipping.Clip};GUI.Label(new Rect(info.x+12,info.y+5,info.width-150,22),actor,actorStyle);int hp=player?run.hp:Mathf.Max(0,battle.enemyHp),maxHp=player?run.maxHp:battle.enemyMaxHp,blockValue=player?run.block:battle.enemyBlock;if(player)GUI.Label(new Rect(info.xMax-126,info.y+5,112,22),$"◆ EN {run.energy}/3",new GUIStyle(body){alignment=TextAnchor.MiddleRight,fontSize=14});else{int intent=battle.enemy.damages[battle.move%battle.enemy.damages.Length]+GameCatalog.Dungeons.First(x=>x.id==run.dungeon).damage;GUI.Label(new Rect(info.xMax-142,info.y+5,128,22),$"攻撃予告  {intent}",new GUIStyle(body){alignment=TextAnchor.MiddleRight,fontSize=14,fontStyle=FontStyle.Bold,normal={textColor=new Color(.65f,.18f,.12f)}});}DrawMeter(new Rect(info.x+12,info.y+30,info.width-24,17),hp/(float)Mathf.Max(1,maxHp),$"♥  {hp} / {maxHp}",battleHpTex);DrawMeter(new Rect(info.x+12,info.y+51,info.width-24,15),Mathf.Clamp01(blockValue/24f),$"盾  防御 {blockValue}",battleBlockTex);DrawStatusIcons(new Rect(info.x+12,info.y+67,info.width-24,17),player?run.statuses:battle.enemyStatuses);}
 void DrawBattleActorArt(Rect target,bool player){GUI.BeginGroup(target);GUI.color=new Color(1f,1f,1f,.18f);DrawDungeonArt(new Rect(0,0,target.width,target.height),run.dungeon);GUI.color=Color.white;float scale=player?1.34f:1.42f,scaledHeight=target.height*scale,y=-(scaledHeight-target.height)*.34f;Rect stage=new(0,y,target.width,scaledHeight);if(player)DrawCharacter(stage,meta.body,meta.hair);else DrawEnemyArt(stage,battle.enemy.id);GUI.EndGroup();}
 void DrawMeter(Rect rect,float value,string label,Texture2D fillTexture){var trackStyle=new GUIStyle(){normal={background=battleMeterTrackTex},border=new RectOffset(8,8,8,8)};var fillStyle=new GUIStyle(){normal={background=fillTexture},border=new RectOffset(8,8,8,8)};GUI.Box(rect,GUIContent.none,trackStyle);float fillWidth=(rect.width-4)*Mathf.Clamp01(value);if(fillWidth>3)GUI.Box(new Rect(rect.x+2,rect.y+2,fillWidth,rect.height-4),GUIContent.none,fillStyle);var meterStyle=new GUIStyle(body){alignment=TextAnchor.MiddleCenter,fontSize=14,fontStyle=FontStyle.Bold,normal={textColor=new Color(.98f,.94f,.84f)}};GUI.Label(rect,label,meterStyle);}
 void DrawStatusIcons(Rect area,List<StatusState> statuses){if(statuses==null||statuses.Count==0){GUI.Label(area,"状態異常なし",new GUIStyle(body){alignment=TextAnchor.MiddleLeft,fontSize=13,normal={textColor=new Color(.42f,.31f,.20f)}});return;}float x=area.x;foreach(var status in statuses.Take(7)){var def=ContentDatabase.Status(status.type);bool debuff=def!=null&&def.kind=="debuff";Rect chip=new(x,area.y-6,29,29);var chipStyle=new GUIStyle(){normal={background=debuff?battleStatusDebuffTex:battleStatusBuffTex},border=new RectOffset(10,10,10,10)};GUI.Box(chip,GUIContent.none,chipStyle);GUI.Label(chip,def?.icon??"●",new GUIStyle(body){alignment=TextAnchor.MiddleCenter,fontSize=15,fontStyle=FontStyle.Bold,normal={textColor=Color.white}});Rect count=new(chip.xMax-9,chip.yMax-11,14,14);GUI.Box(count,GUIContent.none,new GUIStyle(){normal={background=bookButtonSelectedTex},border=new RectOffset(6,6,6,6)});GUI.Label(count,status.amount.ToString(),new GUIStyle(body){alignment=TextAnchor.MiddleCenter,fontSize=10,fontStyle=FontStyle.Bold,normal={textColor=new Color(.24f,.12f,.05f)}});x+=39;}}
 void DrawRoleArt(Rect target,string role){if(roleArt==null)return;int index=RoleArtIndex(role),col=index%4,row=index/4;Rect uv=new(col*.25f,(2-row)/3f,.25f,1f/3f);float aspect=(uv.width*roleArt.width)/(uv.height*roleArt.height);GUI.DrawTextureWithTexCoords(FitAspect(target,aspect),roleArt,uv,true);}
 int RoleArtIndex(string role)=>role=="warrior"?0:role=="guardian"?1:role=="scout"?2:role=="artificer"?3:role=="blade_master"?4:role=="bulwark"?5:role=="hunter"?6:role=="grand_artificer"?7:role=="arsenal_lord"?8:role=="pack_saint"?9:role=="rune_weaver"?10:role=="grid_dancer"?11:role.Contains("knight")?5:role.Contains("druid")?6:role.Contains("artificer")||role.Contains("channeler")?7:0;
 void DrawEnemyArt(Rect target,string enemy){if(enemyArt==null)return;Rect uv=enemy=="sentinel"?new Rect(0,.5f,.174f,.5f):enemy=="rats"?new Rect(.174f,.5f,.172f,.5f):enemy=="porter"?new Rect(.346f,.5f,.172f,.5f):enemy=="mage"?new Rect(.518f,.5f,.172f,.5f):enemy=="beast"?new Rect(0,0,.344f,.5f):enemy=="knight"?new Rect(.344f,0,.347f,.5f):new Rect(.69f,0,.31f,1);float aspect=(uv.width*enemyArt.width)/(uv.height*enemyArt.height);GUI.DrawTextureWithTexCoords(FitAspect(target,aspect),enemyArt,uv,true);}
 void Battle(){var dungeon=GameCatalog.Dungeons.First(x=>x.id==run.dungeon);BeginPage("戦闘",dungeon.name);GUILayout.BeginHorizontal();GUILayout.BeginVertical(GUI.skin.box,GUILayout.Height(180));GUILayout.Label(GameCatalog.Roles[run.role].name,header);GUILayout.Label($"HP {run.hp}/{run.maxHp}　防御 {run.block}",body);GUILayout.Label($"エネルギー {run.energy}/3",header);GUILayout.Label(StatusText(run.statuses),body);GUILayout.EndVertical();GUILayout.Space(20);GUILayout.Label("VS",title,GUILayout.Width(70));GUILayout.Space(20);GUILayout.BeginVertical(GUI.skin.box,GUILayout.Height(180));GUILayout.Label(battle.enemy.name,header);GUILayout.Label($"HP {Mathf.Max(0,battle.enemyHp)}/{battle.enemyMaxHp}",body);GUILayout.Label($"次の行動　攻撃 {battle.enemy.damages[battle.move%battle.enemy.damages.Length]+dungeon.damage}",header);GUILayout.Label(StatusText(battle.enemyStatuses),body);GUILayout.EndVertical();GUILayout.EndHorizontal();GUILayout.Space(8);GUILayout.Label(battle.log,hubLabel,GUILayout.Height(42));if(run.consumables.Count>0){GUILayout.BeginHorizontal();GUILayout.Label("消耗品",header,GUILayout.Width(80));for(int i=0;i<run.consumables.Count;i++){int index=i;if(GUILayout.Button(ConsumableSystem.Name(run.consumables[i]),button,GUILayout.Width(110),GUILayout.Height(44))){ConsumableSystem.Use(run,battle,index);if(battle.enemyHp<=0){EndPage();WinBattle();return;}break;}}GUILayout.EndHorizontal();}GUILayout.Space(18);GUILayout.Label("手札",header);GUILayout.BeginHorizontal();for(int i=0;i<run.hand.Count;i++){int index=i;var c=run.hand[i];GUI.enabled=c.cost<=run.energy;GUI.backgroundColor=c.type==CardType.Attack?new Color(.52f,.20f,.16f):c.type==CardType.Skill?new Color(.16f,.36f,.44f):new Color(.38f,.23f,.48f);if(GUILayout.Button($"{c.cost} EN\n{c.name}\n\n{c.text}\n\n{c.source}",card,GUILayout.Width(165),GUILayout.Height(190))){if(BattleSystem.Play(run,battle,index)){GUI.backgroundColor=Color.white;EndPage();WinBattle();return;}}GUI.backgroundColor=Color.white;GUI.enabled=true;}GUILayout.EndHorizontal();GUILayout.Space(14);GUI.backgroundColor=new Color(.65f,.22f,.17f);if(GUILayout.Button("ターン終了",button,GUILayout.Width(180),GUILayout.Height(56))){GUI.backgroundColor=Color.white;if(BattleSystem.EndTurn(run,battle,dungeon.damage)){EndPage();FinishRun(false);return;}}GUI.backgroundColor=Color.white;EndPage();}
 string StatusText(List<StatusState> statuses)=>statuses==null||statuses.Count==0?"状態変化なし":string.Join("　",statuses.Select(x=>$"{ContentDatabase.Status(x.type)?.name ?? x.type} {x.amount}"));
 void WinBattle(){run.battlesWon++;run.gold+=12+run.battlesWon*3;run.hp=Mathf.Min(run.maxHp,run.hp+3);if(map!=null){var fought=map.nodes.FirstOrDefault(n=>n.id==map.current);if(fought!=null)fought.cleared=true;}if(battle.enemy.tier==3){FinishRun(true);return;}screen=ScreenId.Reward;}
 string rewardSelectionId="",shopSelectionId="";
 void RewardScreen(){
  BeginPage("戦闘報酬","左頁で戦利品を選び、右頁で記録を確かめて獲得します。");
  string[] pool={"dagger","plate","crystal","bomb","spear","buckler","flask","charm"};int start=(run.battlesWon*3)%pool.Length;string[] rewards=Enumerable.Range(0,3).Select(i=>pool[(start+i)%pool.Length]).ToArray();
  if(string.IsNullOrEmpty(rewardSelectionId)||!rewards.Contains(rewardSelectionId))rewardSelectionId=rewards[0];
  float pageWidth=BookPageColumnWidth();
  GUILayout.BeginHorizontal();
  GUILayout.BeginVertical(GUILayout.Width(pageWidth));
  GUILayout.Label("獲得候補",header);GUILayout.Label("未鑑定のまま持ち帰る品を1つ選択します。",body,GUILayout.Height(38));GUILayout.Space(8);
  foreach(string id in rewards){if(RewardShopItemRow(id,"未鑑定",rewardSelectionId==id))rewardSelectionId=id;GUILayout.Space(7);}
  GUILayout.EndVertical();GUILayout.Space(BookPageGutter());
  GUILayout.BeginVertical(GUILayout.Width(pageWidth));
  GUILayout.Label("戦利品の記録",header);DrawRewardShopItemDetail(rewardSelectionId,"帰還後に鑑定され、保管庫へ追加されます。");GUILayout.Space(14);
  if(GUILayout.Button("この戦利品を獲得する",button,GUILayout.Height(56))){run.lootBag.Add(new ItemInstance(rewardSelectionId){identified=false});rewardSelectionId="";screen=ScreenId.Map;}
  GUILayout.EndVertical();GUILayout.EndHorizontal();EndPage();
 }
 void ShopScreen(){
  BeginPage("行商人",$"所持金 {run.gold}G　・　左頁の商品を選び、右頁で確認して購入します。");
  string[] stock=GameCatalog.Items.Keys.Take(5).ToArray();if(string.IsNullOrEmpty(shopSelectionId)||!stock.Contains(shopSelectionId))shopSelectionId=stock[0];float pageWidth=BookPageColumnWidth();
  GUILayout.BeginHorizontal();
  GUILayout.BeginVertical(GUILayout.Width(pageWidth));
  GUILayout.Label("本日の品書き",header);GUILayout.Label($"所持金　{run.gold}G",new GUIStyle(body){fontSize=17,fontStyle=FontStyle.Bold},GUILayout.Height(28));GUILayout.Space(5);
  foreach(string id in stock){var item=GameCatalog.Items[id];int price=14+item.cells.Length*4;if(RewardShopItemRow(id,$"{price}G",shopSelectionId==id))shopSelectionId=id;GUILayout.Space(5);}
  GUILayout.EndVertical();GUILayout.Space(BookPageGutter());
  GUILayout.BeginVertical(GUILayout.Width(pageWidth));
  GUILayout.Label("商品の記録",header);var selected=GameCatalog.Items[shopSelectionId];int selectedPrice=14+selected.cells.Length*4;DrawRewardShopItemDetail(shopSelectionId,$"価格　{selectedPrice}G\n購入品は未鑑定のまま戦利品袋に入ります。");if(!string.IsNullOrEmpty(message)&&message.StartsWith("購入"))GUILayout.Label(message,new GUIStyle(body){fontStyle=FontStyle.Bold,normal={textColor=new Color(.18f,.43f,.22f)}},GUILayout.Height(27));GUILayout.Space(8);
  GUI.enabled=run.gold>=selectedPrice;if(GUILayout.Button(run.gold>=selectedPrice?$"{selectedPrice}Gで購入する":"所持金が足りません",button,GUILayout.Height(54))){run.gold-=selectedPrice;run.lootBag.Add(new ItemInstance(shopSelectionId){identified=false});message=$"購入完了：{selected.name}　残金 {run.gold}G";}GUI.enabled=true;
  GUILayout.Space(8);if(GUILayout.Button("マップへ戻る",button,GUILayout.Height(48))){shopSelectionId="";screen=ScreenId.Map;}
  GUILayout.EndVertical();GUILayout.EndHorizontal();EndPage();
 }
 bool RewardShopItemRow(string id,string note,bool selected){var item=GameCatalog.Items[id];Rect row=GUILayoutUtility.GetRect(1,68,GUILayout.ExpandWidth(true),GUILayout.Height(68));DrawBookEntrySurface(row,selected);Rect art=new(row.x+8,row.y+6,56,56);DrawItemArt(art,id);Color text=selected?new Color(.55f,.27f,.06f):new Color(.25f,.15f,.08f);GUI.Label(new Rect(row.x+76,row.y+8,row.width-148,27),item.name,new GUIStyle(header){fontSize=16,clipping=TextClipping.Clip,normal={textColor=text}});GUI.Label(new Rect(row.x+77,row.y+36,row.width-150,20),$"{ItemTypeName(item.type)}　・　{item.cells.Length}マス",new GUIStyle(body){fontSize=12,clipping=TextClipping.Clip});GUI.Label(new Rect(row.xMax-70,row.y+19,58,27),note,new GUIStyle(body){alignment=TextAnchor.MiddleCenter,fontSize=12,fontStyle=FontStyle.Bold,normal={textColor=text}});return GUI.Button(row,GUIContent.none,hotspot);}
 void DrawRewardShopItemDetail(string id,string note){var item=GameCatalog.Items[id];float artHeight=BookDetailArtHeight(220f);Rect panel=GUILayoutUtility.GetRect(1,artHeight,GUILayout.ExpandWidth(true),GUILayout.Height(artHeight));DrawBookEntrySurface(panel,true);Rect artArea=new(panel.x+18,panel.y+12,panel.width-36,panel.height-24);DrawItemArt(FitAspect(artArea,1f),id);GUILayout.Space(8);GUILayout.Label(item.name,new GUIStyle(header){fontSize=24});GUILayout.Label($"{ItemTypeName(item.type)}　・　{item.cells.Length}マス",new GUIStyle(body){fontSize=13,fontStyle=FontStyle.Bold});GUILayout.Space(5);GUILayout.Label(item.description,body,GUILayout.MinHeight(42));GUILayout.Space(7);GUILayout.Label(note,new GUIStyle(body){fontSize=13,wordWrap=true});}
