  GUI.Label(new Rect(headerRect.x+Us(25),headerRect.yMax-Us(38),headerRect.width*.57f,Us(27)),string.IsNullOrEmpty(message)?"地図上の円を選び、下の行動欄で移動します。":message,new GUIStyle(screenSubtitle){fontSize=Fs(15),fontStyle=FontStyle.Bold,clipping=TextClipping.Overflow,normal={textColor=muted}});
  GUI.Label(new Rect(headerRect.xMax-headerRect.width*.27f,headerRect.y+Us(18),headerRect.width*.23f,Us(30)),"探索圧力は地図右下の方位盤に記録",new GUIStyle(screenSubtitle){fontSize=Fs(13),fontStyle=FontStyle.Bold,alignment=TextAnchor.MiddleCenter,normal={textColor=muted}});
