a.currentRole?gold:new Color(.49f,.36f,.18f),3);GUILayout.Label($"{selectedRole.name}　Lv.{selectedLevel.value}/{selectedRole.maxLevel}",new GUIStyle(header){fontSize=24});GUILayout.Label(selectedRole.kind+"\n\n"+selectedRole.description,body);GUILayout.Space(12);GUILayout.Label("成長効果",header);DrawRoleMilestone(1,selectedLevel.value,"基礎効果",selectedRole.description);DrawRoleMilestone(7,selectedLevel.value,"専用効果",RoleMilestoneText(selectedRole.id,false));DrawRoleMilestone(selectedRole.maxLevel,selectedLevel.value,"最大レベル効果",RoleMilestoneText(selectedRole.id,true));GUILayout.Space(10);if(selectedRole.id==meta.currentRole)GUILayout.Label("● 現在の役職",hubLabel,GUILayout.Height(44));else GUILayout.Label("転職は専用イベントまたは施設から行います",body);GUILayout.EndVertical();GUILayout.EndHorizontal();EndPage();}
