 string RoleMilestoneText(string id,bool maximum){if(id.Contains("guardian")||id.Contains("bulwark")||id.Contains("knight"))return maximum?"戦闘開始時に防御を得て、余剰防御を次のターンへ一部持ち越す。":"防御カードを連続使用すると次の防御効果が上昇する。";if(id.Contains("scout")||id.Contains("hunter")||id.Contains("blade")||id.Contains("dancer"))return maximum?"各戦闘で最初に使う0コストカードを複製する。":"異なる装備由来のカードを続けて使うと追加ドロー。";if(id.Contains("artificer")||id.Contains("rune")||id.Contains("channeler"))return maximum?"戦闘中に最初に使うルーン・道具カードの耐久を消費しない。":"属性一致が3色以上なら戦闘開始時にエネルギーを得る。";return maximum?"武器カードを一定回数使うたび、ラン中の攻撃力が成長する。":"同じ武器由来のカードを続けて使うと追加ダメージ。";}
 void FactionScreenBook(){Back();BeginPage("勢力記録","左頁の関係図から勢力を選び、右頁で階級と恩恵を確認します。");if(string.IsNullOrEmpty(selectedFactionId)||!GameCatalog.Factions.Any(x=>x.id==selectedFactionId))selectedFactionId=meta.currentFaction;var selected=Faction(selectedFactionId);float rep=meta.factionRep.FirstOrDefault(x=>x.id==selected.id)?.value??0;GUILayout.BeginHorizontal();GUILayout.BeginVertical(GUI.skin.box,GUILayout.Width(BookPageColumnWidth()));GUILayout.Label("現在の勢力関係",header);DrawFactionRelationMap();GUILayout.Space(8);GUILayout.Label("金線：協調　　赤線：競合",new GUIStyle(body){alignment=TextAnchor.MiddleCenter,fontStyle=FontStyle.Bold});GUILayout.Label("円の大きさは貢献度と影響力を表します。勢力を選ぶと右頁の記録が切り替わります。",screenSubtitle);GUILayout.EndVertical();GUILayout.Space(BookPageGutter());GUILayout.BeginVertical(GUI.skin.box,GUILayout.Width(BookPageColumnWidth()));float artHeight=BookDetailArtHeight(210f);Rect art=GUILayoutUtility.GetRect(1,artHeight,GUILayout.ExpandWidth(true),GUILayout.Height(artHeight));DrawFactionArt(art,selected.id);DrawOutline(art,selected.id==meta.currentFaction?gold:new Color(.48f,.35f,.18f),3);GUILayout.Label(selected.name,new GUIStyle(header){fontSize=25});GUILayout.Label(selected.description,body);GUILayout.Space(8);int rankIndex=Mathf.Clamp(Mathf.FloorToInt(rep/25f),0,selected.ranks.Length-1);GUILayout.Label($"現在階級　{selected.ranks[rankIndex]}　／　貢献度 {rep:0}",header);Rect progress=GUILayoutUtility.GetRect(1,12,GUILayout.ExpandWidth(true),GUILayout.Height(12));GUI.color=new Color(.26f,.17f,.09f,.28f);GUI.DrawTexture(progress,Texture2D.whiteTexture);GUI.color=new Color(.68f,.40f,.12f,.86f);GUI.DrawTexture(new Rect(progress.x,progress.y,progress.width*Mathf.Clamp01(rep/Mathf.Max(25f,(selected.ranks.Length-1)*25f)),progress.height),Texture2D.whiteTexture);GUI.color=Color.white;for(int i=0;i<selected.ranks.Length;i++)GUILayout.Label($"{(i<=rankIndex?"●":"○")} {i*25,3}　{selected.ranks[i]}",body);GUILayout.Space(9);GUILayout.Label("主な関係",header);foreach(var faction in GameCatalog.Factions.Where(x=>x.id!=selected.id))GUILayout.Label($"{faction.name}　{FactionRelationDetail(selected.id,faction.id)}",body);GUILayout.Space(12);GUI.enabled=meta.currentFaction!=selected.id&&meta.baseGold>=20;if(GUILayout.Button(meta.currentFaction==selected.id?"● 所属中":"20Gで所属を変更",button,GUILayout.Height(52))){meta.baseGold-=20;meta.currentFaction=selected.id;SaveSystem.Save(meta);}GUI.enabled=true;GUILayout.EndVertical();GUILayout.EndHorizontal();EndPage();}
 void DrawFactionRelationMap(){Rect mapRect=GUILayoutUtility.GetRect(BookPageColumnWidth(),360,GUILayout.Width(BookPageColumnWidth()),GUILayout.Height(360));GUI.Box(mapRect,GUIContent.none,bookEntryStyle);var factions=GameCatalog.Factions.Take(4).ToArray();Vector2[] positions={new(mapRect.x+mapRect.width*.28f,mapRect.y+mapRect.height*.27f),new(mapRect.x+mapRect.width*.72f,mapRect.y+mapRect.height*.27f),new(mapRect.x+mapRect.width*.28f,mapRect.y+mapRect.height*.73f),new(mapRect.x+mapRect.width*.72f,mapRect.y+mapRect.height*.73f)};for(int i=0;i<factions.Length;i++)for(int j=i+1;j<factions.Length;j++){bool friendly=FactionFriendly(factions[i].id,factions[j].id);DrawMapLineV2(positions[i],positions[j],friendly?new Color(.65f,.45f,.13f,.52f):new Color(.57f,.17f,.13f,.38f),friendly?5f:3f);}for(int i=0;i<factions.Length;i++){var faction=factions[i];float value=meta.factionRep.FirstOrDefault(x=>x.id==faction.id)?.value??0;float size=Mathf.Clamp(76f+value*.35f,72f,112f);Rect node=new(positions[i].x-size*.5f,positions[i].y-size*.5f,size,size);bool chosen=faction.id==selectedFactionId;GUI.Box(new Rect(node.x-5,node.y-5,node.width+10,node.height+10),GUIContent.none,chosen?bookEntrySelectedStyle:bookEntryStyle);DrawFactionArt(node,faction.id);DrawOutline(node,faction.id==meta.currentFaction?gold:chosen?new Color(.72f,.42f,.10f):new Color(.40f,.27f,.14f),faction.id==meta.currentFaction?4:2);Rect label=new(node.center.x-74,node.yMax+3,148,39);GUI.Box(label,GUIContent.none,bookEntryStyle);GUI.Label(new Rect(label.x+4,label.y+2,label.width-8,18),faction.name,new GUIStyle(body){fontSize=13,fontStyle=FontStyle.Bold,alignment=TextAnchor.MiddleCenter,clipping=TextClipping.Clip});GUI.Label(new Rect(label.x+4,label.y+19,label.width-8,17),$"貢献 {value:0}"+(faction.id==meta.currentFaction?"　所属":""),new GUIStyle(screenSubtitle){fontSize=10,alignment=TextAnchor.MiddleCenter});if(GUI.Button(new Rect(node.x-7,node.y-7,node.width+14,node.height+58),GUIContent.none,hotspot))selectedFactionId=facti