 void CompendiumScreenBook(){Back();BeginPage("図鑑","左頁のカードを選ぶと、右頁に詳しい記録が開きます。");float tabWidth=Mathf.Max(58f,(BookPageColumnWidth()-16f)/3f);GUILayout.BeginHorizontal(GUILayout.Width(BookPageColumnWidth()));string[] tabs={"装備","役職","敵"};for(int i=0;i<tabs.Length;i++){int tab=i;if(GUILayout.Button((compendiumTab==i?"● ":"")+tabs[i],compendiumTab==i?navSelected:navButton,GUILayout.Width(tabWidth),GUILayout.Height(44))){compendiumTab=tab;selectedCompendiumId="";}}GUILayout.EndHorizontal();GUILayout.Space(10);GUILayout.BeginHorizontal();GUILayout.BeginVertical(GUI.skin.box,GUILayout.Width(BookPageColumnWidth()));GUILayout.Label(tabs[compendiumTab]+"一覧",header);if(compendiumTab==0)DrawCompendiumItemGrid();else if(compendiumTab==1)DrawCompendiumRoleGrid();else DrawCompendiumEnemyGrid();GUILayout.EndVertical();GUILayout.Space(BookPageGutter());GUILayout.BeginVertical(GUI.skin.box,GUILayout.Width(BookPageColumnWidth()));DrawCompendiumDetail();GUILayout.EndVertical();GUILayout.EndHorizontal();EndPage();}
